33	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
34	
35	const COMPONENT_BLOCK_SIZE = 3;
36	const COMPONENT_BLOCK_PRICE = 60;
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
40	
41	const sumBasePrices = (items: Item[]): number =>
42	  items.reduce((s, i) => s + basePriceFor(i), 0);
43	
44	const groupByType = (items: Item[]): Map<string, Item[]> => {
45	  const map = new Map<string, Item[]>();
46	  for (const item of items) {
47	    const list = map.get(item.type) ?? [];
48	    list.push(item);
49	    map.set(item.type, list);
50	  }
51	  return map;
52	};
53	
54	const priceForComponentGroup = (group: Item[]): number =>
55	  group.length === COMPONENT_BLOCK_SIZE
56	    ? COMPONENT_BLOCK_PRICE
57	    : sumBasePrices(group);
58	
59	const componentsPremium = (components: Item[]): number =>
60	  Array.from(groupByType(components).values())
61	    .reduce((sum, group) => sum + priceForComponentGroup(group), 0);
62	
63	const itemsBasePremium = (items: Item[]): number => {
64	  const components = items.filter(isComponent);
65	  const nonComponents = items.filter((i) => !isComponent(i));
66	  return sumBasePrices(nonComponents) + componentsPremium(components);
67	};
