69	const CURSE_SURCHARGE_RATE = 0.5;
70	const HIGH_ENCHANTMENT_RATE = 0.3;
71	const HIGH_ENCHANTMENT_THRESHOLD = 5;
72	const FIRST_INSURANCE_RATE = 0.1;
73	
74	const perItemSurchargeRate = (item: Item): number =>
75	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
76	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0);
77	
78	const itemSurcharges = (items: Item[]): number =>
79	  items.reduce((sum, item) => sum + basePriceFor(item) * perItemSurchargeRate(item), 0);
