81	const quotePremium = (step: QuoteStep): number => {
82	  const base = itemsBasePremium(step.items);
83	  const surcharges = itemSurcharges(step.items);
84	  const firstInsurance = base * FIRST_INSURANCE_RATE;
85	  const total = base + surcharges + firstInsurance + PROCESSING_FEE;
86	  return Math.ceil(total);
87	};
